const request = $('Update Refund Status Webhook').first()?.json ?? $input.first()?.json ?? {};
const body = request.body ?? request.query ?? {};
const headers = request.headers ?? {};
const settings = $('Load Global Settings').first()?.json ?? {};
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const deriveBaseUrl = (headers, fallback) => {
  const forwardedProto = clean(headers['x-forwarded-proto']);
  const forwardedHost = clean(headers['x-forwarded-host']);
  const host = forwardedHost || clean(headers.host);
  const forwardedPort = clean(headers['x-forwarded-port']);
  if (!host) return fallback;
  const proto = forwardedProto || 'http';
  let authority = host;
  if (forwardedPort && !authority.includes(':')) {
    const isDefaultPort = (proto === 'http' && forwardedPort === '80') || (proto === 'https' && forwardedPort === '443');
    if (!isDefaultPort) authority = `${authority}:${forwardedPort}`;
  }
  return `${proto}://${authority}`;
};
const fallbackBaseUrl = clean(settings.n8n_base_url) || 'http://n8n:5678';
const n8nBaseUrl = deriveBaseUrl(headers, fallbackBaseUrl);
const validStatuses = ['New Request', 'Request Bank Details', 'Bank Details Obtained', 'Submitted for Refund', 'Refund Processed', 'Refund Rejected'];
const id = Number.parseInt(clean(body.id), 10);
const action = clean(body.action) || 'update_status';
const status = clean(body.status);
const notes = clean(body.notes);
const requestEmailMessageId = clean(body.request_email_message_id);
const bankDetailsMessageId = clean(body.bank_details_message_id);
const treasuryEmailMessageId = clean(body.treasury_email_message_id);
const returnUrl = clean(body.return_url) || `${n8nBaseUrl}/webhook/refunds${Number.isInteger(id) ? `?id=${id}` : ''}`;
const errorMessage = !Number.isInteger(id)
  ? 'Refund id is required.'
  : !['update_status', 'delete'].includes(action)
    ? 'Action must be update_status or delete.'
    : action !== 'delete' && !status
      ? 'Status is required.'
      : action !== 'delete' && !validStatuses.includes(status)
        ? `Status must be one of: ${validStatuses.join(', ')}`
        : '';
return [{ json: { id, action, status, notes, request_email_message_id: requestEmailMessageId, bank_details_message_id: bankDetailsMessageId, treasury_email_message_id: treasuryEmailMessageId, error_message: errorMessage, return_url: returnUrl, n8n_base_url: n8nBaseUrl } }];

const input = $('Resolve Update Request').first().json ?? {};
const message = input.error_message || 'Unable to update refund status.';
const redirectTo = `${input.return_url || '#'}${(input.return_url || '').includes('?') ? '&' : '?'}error=${encodeURIComponent(message)}`;
const escapeHtml = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\"/g, '&quot;').replace(/'/g, '&#39;');
const html = `<!doctype html><html lang="en"><head><meta charset="utf-8"><meta http-equiv="refresh" content="0; url=${escapeHtml(redirectTo)}"><meta name="viewport" content="width=device-width, initial-scale=1"><title>Refund Status Update Failed</title><style>body{margin:0;padding:24px;background:#f7f8fc;font-family:Lato,'Helvetica Neue',Arial,sans-serif;color:#2e3d4e}.panel{max-width:760px;margin:0 auto;background:#fff;border:1px solid #e2e8f0;border-radius:18px;box-shadow:0 18px 40px rgba(53,72,91,.08);padding:28px}.button{display:inline-flex;align-items:center;justify-content:center;padding:12px 18px;border-radius:999px;text-decoration:none;font-weight:700;background:linear-gradient(135deg,#509ee3 0%,#2f80d8 100%);color:#fff}</style></head><body><div class="panel"><h1>Refund Status Update Failed</h1><p>${escapeHtml(message)}</p><p><a class="button" href="${escapeHtml(redirectTo)}">Back to refunds</a></p></div></body></html>`;
return [{ json: { html } }];

const item = $('Resolve Update Request').first().json ?? {};
const sqlLiteral = (value) => {
  if (value === null || value === undefined || value === '') return 'NULL';
  return "'" + String(value).replace(/'/g, "''") + "'";
};
let sql;
if (item.action === 'delete') {
  sql = `DELETE FROM public.refunds WHERE id = ${item.id} RETURNING id, refund_for;`;
} else {
  const sqlParts = [`status = ${sqlLiteral(item.status)}`];
  if (item.request_email_message_id) sqlParts.push(`request_email_message_id = ${sqlLiteral(item.request_email_message_id)}`);
  if (item.bank_details_message_id) sqlParts.push(`bank_details_message_id = ${sqlLiteral(item.bank_details_message_id)}`);
  if (item.treasury_email_message_id) sqlParts.push(`treasury_email_message_id = ${sqlLiteral(item.treasury_email_message_id)}`);
  if (item.status === 'Refund Processed') sqlParts.push('paid_at = now()');
  if (item.status === 'Refund Rejected') sqlParts.push('rejected_at = now()');
  if (item.notes) sqlParts.push(`notes = ${sqlLiteral(item.notes)}`);
  sqlParts.push('updated_at = now()');
  sql = `UPDATE public.refunds SET ${sqlParts.join(', ')} WHERE id = ${item.id} RETURNING id, status, refund_for, membership, refund;`;
}
return [{ json: { sql, ...item } }];

const item = $('Resolve Update Request').first().json ?? {};
const updated = $('Update Refund Status').first()?.json ?? {};
const isDelete = item.action === 'delete';
const message = isDelete
  ? (updated.id ? `Refund ${updated.id} deleted` : 'Refund deleted')
  : (updated.id ? `Refund ${updated.id} updated to ${updated.status || item.status}` : 'Refund status updated');
const redirectBase = isDelete ? (item.n8n_base_url ? `${item.n8n_base_url}/webhook/refunds` : '#') : (item.return_url || '#');
const redirectTo = `${redirectBase}${redirectBase.includes('?') ? '&' : '?'}message=${encodeURIComponent(message)}${isDelete ? '' : `&id=${encodeURIComponent(updated.id || item.id)}`}`;
const escapeHtml = (value) => String(value ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/\"/g, '&quot;').replace(/'/g, '&#39;');
const title = isDelete ? 'Refund Deleted' : 'Refund Status Updated';
const html = `<!doctype html><html lang="en"><head><meta charset="utf-8"><meta http-equiv="refresh" content="0; url=${escapeHtml(redirectTo)}"><meta name="viewport" content="width=device-width, initial-scale=1"><title>${title}</title><style>body{margin:0;padding:24px;background:#f7f8fc;font-family:Lato,'Helvetica Neue',Arial,sans-serif;color:#2e3d4e}.panel{max-width:760px;margin:0 auto;background:#fff;border:1px solid #e2e8f0;border-radius:18px;box-shadow:0 18px 40px rgba(53,72,91,.08);padding:28px}.button{display:inline-flex;align-items:center;justify-content:center;padding:12px 18px;border-radius:999px;text-decoration:none;font-weight:700;background:linear-gradient(135deg,#509ee3 0%,#2f80d8 100%);color:#fff}</style></head><body><div class="panel"><h1>${title}</h1><p>Returning to refunds…</p><p><a class="button" href="${escapeHtml(redirectTo)}">Continue</a></p></div></body></html>`;
return [{ json: { html } }];
